mapper.select:
SELECT t1.ID, t1.EQUIP_PLAN_ID, t1.PLAN_TYPE, t1.EQUIP_ID, t1.EQUIP_NAME, t1.START_DATE, t1.END_DATE, t1.INITIAL_NUMBER, t1.DEADLINE_NUMBER, t1.INSPECTOR_ID, t1.INSPECTOR_NAME, t1.STATUS, t2.EQUIP_SMALL_CATEGORY_ID, t2.EQUIP_SMALL_CATEGORY_NAME, t2.TIME_LIMIT, t2.EQUIP_TYPE, t1.CREATE_BY_NAME, t1.CREATE_TIME FROM E_PM_MAINTAIN_TASK T1 LEFT JOIN E_PM_MAINTAIN_PLAN T2 ON T2.ID = T1.EQUIP_PLAN_ID where 1=1
and T1.START_DATE >= to_date(#{startTime},'yyyy-MM-dd')
and T1.START_DATE <= to_date(#{endTime},'yyyy-MM-dd')
and t2.EQUIP_SMALL_CATEGORY_ID = #{equipSmallCategoryId}
and t2.EQUIP_TYPE = #{equipType}
and t1.PLAN_TYPE = #{planType}
and t1.STATUS = #{status}
and t1.EQUIP_ID = #{equipId}
and t1.EQUIP_NAME like #{equipNameLike}
order by t1.CREATE_TIME DESC

SELECT distinct t1.ID, t1.EQUIP_PLAN_ID, t1.PLAN_TYPE, t1.EQUIP_ID, t1.EQUIP_NAME, t1.START_DATE, t1.END_DATE, t1.INITIAL_NUMBER, t1.DEADLINE_NUMBER, t1.INSPECTOR_ID, t1.INSPECTOR_NAME, t1.STATUS, t2.EQUIP_SMALL_CATEGORY_ID, t2.EQUIP_SMALL_CATEGORY_NAME, t2.TIME_LIMIT, t2.EQUIP_TYPE, t1.CREATE_BY_NAME, t1.CREATE_TIME FROM E_PM_MAINTAIN_TASK T1 LEFT JOIN E_PM_MAINTAIN_PLAN T2 ON T2.ID = T1.EQUIP_PLAN_ID LEFT JOIN E_PM_MAINTAIN_TASK_ITEM T3 ON T3.EQUIP_TASK_ID = T1.ID where 1=1
and T1.START_DATE >= to_date(#{startTime},'yyyy-MM-dd')
and T1.START_DATE <= to_date(#{endTime},'yyyy-MM-dd')
and t2.EQUIP_SMALL_CATEGORY_ID = #{equipSmallCategoryId}
and t2.EQUIP_TYPE = #{equipType}
and t1.PLAN_TYPE = #{planType}
and instr( #{status}, t1.STATUS) > 0
and t1.EQUIP_ID = #{equipId}
and t1.INSPECTOR_ID = #{inspectorId}
and t1.EQUIP_NAME like #{equipNameLike}
and t3.EQUIP_INSTITUTION_ID = #{equipInstitutionId}
and t3.EQUIP_UNIT_ID = #{equipUnitId}
order by t1.CREATE_TIME DESC

select
distinct
EQUIP_INSTITUTION_ID "value",
EQUIP_INSTITUTION_NAME "label"
from
E_PM_MAINTAIN_TASK_ITEM
where
EQUIP_TASK_ID = #{id}

    and EQUIP_INSTITUTION_ID = #{equipInstitutionId}


    and EQUIP_UNIT_ID = #{equipUnitId}

select distinct EQUIP_INSTITUTION_ID "equipInstitutionId", EQUIP_INSTITUTION_NAME "equipInstitutionName", EQUIP_UNIT_ID "value", EQUIP_UNIT_NAME "label" from E_PM_MAINTAIN_TASK_ITEM where EQUIP_TASK_ID = #{id}
and EQUIP_INSTITUTION_ID = #{equipInstitutionId}
and EQUIP_UNIT_ID = #{equipUnitId}

SELECT t1.ID, t1.EQUIP_TASK_ID, t1.EQUIP_SMALL_CATEGORY_ID, t1.EQUIP_SMALL_CATEGORY_NAME, t1.EQUIP_INSTITUTION_ID, t1.EQUIP_INSTITUTION_NAME, t1.EQUIP_UNIT_ID, t1.EQUIP_UNIT_NAME, t1.CONTENT, t1.STANDARD, t1.IS_ABNORMAL, t1.REMARK, t2.EQUIP_ID, t2.EQUIP_NAME, t2.PLAN_TYPE, t1.STATUS, t1.EQUIP_TYPE, t1.IS_REPAIR FROM E_PM_MAINTAIN_TASK_ITEM t1 LEFT JOIN E_PM_MAINTAIN_TASK t2 on t2.ID = t1.EQUIP_TASK_ID where t1.EQUIP_TASK_ID = #{id}
and t1.EQUIP_INSTITUTION_ID = #{equipInstitutionId}
and t1.EQUIP_UNIT_ID = #{equipUnitId}

mapper.update:
begin
UPDATE E_PM_MAINTAIN_TASK_ITEM SET IS_ABNORMAL = #{item.isAbnormal,jdbcType=INTEGER}, STATUS = 1, REMARK = #{item.remark,jdbcType=VARCHAR}, IS_REPAIR = #{item.isRepair,jdbcType=INTEGER}, UPDATE_BY = #{item.loginUserId, jdbcType=BIGINT}, UPDATE_BY_NAME = #{item.loginUserName, jdbcType=VARCHAR}, UPDATE_TIME = #{item.now}
ID = #{item.id,jdbcType=BIGINT} ;
end;

update E_PM_MAINTAIN_TASK
set
STATUS = #{status}
where
ID = #{equipTaskId}
